"""Markdown-индекс сохранённых документов: ## имя файла, описание, Date:, Tags:."""from __future__ import annotationsfrom datetime import datefrom pathlib import Pathfrom urllib.parse import quotefrom src.modules.markdown.models import MarkdownDocumentdef result_relative_md_path(doc: MarkdownDocument) -> str:    """Относительный путь .md в каталоге result (как при записи файла)."""    rel_path = (doc.relative_path or "").strip().replace("\\", "/")    if not rel_path:        rel_path = f"{Path(doc.filename).stem}.md"    return rel_pathdef _index_sort_key(doc: MarkdownDocument) -> tuple[float | int, str]:    """Ключ сортировки индекса: новые даты выше; без даты / невалидная дата — в конце, затем по пути."""    path = result_relative_md_path(doc).lower()    raw = (doc.date or "").strip()    if len(raw) >= 10:        try:            y, m, d = int(raw[0:4]), int(raw[5:7]), int(raw[8:10])            return (date(y, m, d).toordinal(), path)        except ValueError:            pass    return (float("-inf"), path)class DocumentsIndexFile:    """Собирает содержимое index.md по списку MarkdownDocument."""    def __init__(self, documents: list[MarkdownDocument]) -> None:        self._documents = list(documents)    def render(self) -> str:        """Текст index.md: H1 и блоки «## [файл](href) / описание / Date: … / Tags: …»."""        lines: list[str] = ["# Индекс документов", ""]        sorted_docs = sorted(            self._documents,            key=_index_sort_key,            reverse=True,        )        blocks: list[str] = []        for doc in sorted_docs:            blocks.append(self._render_entry(doc))        lines.append("\n\n".join(blocks))        lines.append("")        return "\n".join(lines)    @staticmethod    def _render_entry(doc: MarkdownDocument) -> str:        rel = result_relative_md_path(doc)        href = quote(rel, safe="/")        file_name = Path(rel).name        heading = f"## [{file_name}]({href})"        desc = DocumentsIndexFile._one_line(doc.description)        date_val = (doc.date or "").strip()        tags = doc.tags or []        tags_str = ", ".join(tags) if tags else ""        date_line = f"Date: {date_val}"        tags_line = f"Tags: {tags_str}"        return "\n".join([heading, desc, date_line, tags_line])    @staticmethod    def _one_line(value: str | None) -> str:        if not value or not str(value).strip():            return ""        return " ".join(str(value).strip().split())